  <svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">BNB Chains neue KI-Layer-1 · Roadmap &amp; Ziel-Durchsatz vs. BSC</text>
    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="13" font-weight="700">① Roadmap-Zeitplan</text>
      <line x1="70" y1="105" x2="630" y2="105" stroke="rgba(255,255,255,.15)" stroke-width="2"/>
      <circle cx="140" cy="105" r="8" fill="#f0b90b"/>
      <text x="140" y="86" fill="#a1a1aa" font-size="13" text-anchor="middle">Angekündigt</text>
      <text x="140" y="130" fill="#a1a1aa" font-size="13" text-anchor="middle">2026-07-08</text>
      <circle cx="380" cy="105" r="8" fill="#4ade80"/>
      <text x="380" y="86" fill="#a1a1aa" font-size="13" text-anchor="middle">Öffentliches Testnet</text>
      <text x="380" y="130" fill="#a1a1aa" font-size="13" text-anchor="middle">Ende 2026</text>
      <circle cx="590" cy="105" r="9" fill="#f97316" stroke="#fafafa" stroke-width="2"/>
